1	\chapter{Moduli space of curves}
2	\label{chap:moduli}
3	% archon:covers MR4276287UniformityInMordellLangForCurves/ModuliSpace.lean
4	
5	This chapter establishes the fine moduli space \(\mathbb{M}_g\) of smooth genus-\(g\) curves
6	with level structure, together with the universal curve over it and the Torelli map to the
7	moduli of principally polarized abelian varieties. These objects provide the ambient setting
8	for \cref{def:ambient_setup}.
9	
10	\section{Level structure and the fine moduli space}
11	
12	\begin{definition}[Level structure]
13	  \label{def:level_structure}
14	  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.levelStructure}
15	  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
16	  % SOURCE QUOTE: "$\mathbb{M}_g$ denotes the fine moduli space of smooth curves of genus $g$, with level-$\ell$-structure where $\ell\ge \bestlevel$ is fixed, \textit{cf.} \cite[Chapter~XVI, Theorem~2.11 (or above Proposition~2.8)]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or \cite[Theorem 1.8]{OortSteenbrink}."
17	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex); formal definition in \cite[Theorem~1.8]{OortSteenbrink}.}
18	  Fix integers \(g \ge 2\) and \(\ell \ge 3\). A \emph{level-\(\ell\) structure} on a smooth
19	  projective curve \(C\) of genus \(g\) is an isomorphism of group schemes
20	  \[
21	    \mathrm{Jac}(C)[\ell] \xrightarrow{\;\sim\;} (\mathbb{Z}/\ell\mathbb{Z})^{2g}
22	  \]
23	  compatible with the Weil pairing on \(\mathrm{Jac}(C)[\ell]\). Here \(\mathrm{Jac}(C)[\ell]\)
24	  denotes the \(\ell\)-torsion subgroup scheme of the Jacobian.
25	\end{definition}
26	
27	\begin{definition}[Fine moduli space with level structure]
28	  \label{def:Mg_level}
29	  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.mgLevel}
30	  \uses{def:level_structure}
31	  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
32	  % SOURCE QUOTE: "Recall from $\mathsection$\ref{subsec:hgtineqnondeg} that $\mathbb{M}_g$ denotes the fine moduli space of smooth curves of genus $g$, with level-$\ell$-structure where $\ell\ge \bestlevel$ is fixed, \textit{cf.} \cite[Chapter~XVI, Theorem~2.11 (or above Proposition~2.8)]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or \cite[Theorem 1.8]{OortSteenbrink}."
33	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
34	  Fix \(g \ge 2\) and \(\ell \ge 3\). The \emph{fine moduli space} \(\mathbb{M}_g\) of smooth
35	  genus-\(g\) curves with level-\(\ell\) structure is a scheme over
36	  \(\mathrm{Spec}\,\mathbb{Z}[1/\ell]\) that represents the moduli functor
37	  associating to each \(\mathrm{Spec}\,\mathbb{Z}[1/\ell]\)-scheme \(T\) the set of
38	  isomorphism classes of pairs \((C \to T, \alpha)\), where \(C \to T\) is a smooth proper
39	  curve of genus \(g\) and \(\alpha\) is a level-\(\ell\) structure on \(C\). For \(\ell \ge 3\),
40	  this functor is representable, so \(\mathbb{M}_g\) is a fine (not merely coarse) moduli scheme.
41	\end{definition}
42	
43	\begin{definition}[Universal curve]
44	  \label{def:universal_curve}
45	  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.universalCurve}
46	  \uses{def:Mg_level}
47	  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
48	  % SOURCE QUOTE: "There exists a universal curve $\mathfrak{C}_g$ over $\mathbb{M}_g$, it is smooth and proper over $\mathbb{M}_g$ and its fibers are smooth curves of genus $g$. Moreover, $\mathfrak{C}_g\rightarrow \mathbb{M}_g$ is projective, \textit{cf.} \cite[Corollary to Theorem 1.2]{DM:irreducibility} or \cite[Remark 2, \S 9.3]{NeronModels}."
49	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
50	  There exists a \emph{universal curve} \(\mathfrak{C}_g \to \mathbb{M}_g\): a smooth proper
51	  projective morphism of relative dimension \(1\) whose geometric fibers are smooth curves of
52	  genus \(g\). By the fine moduli property of \(\mathbb{M}_g\), the pair
53	  \((\mathbb{M}_g, \mathfrak{C}_g)\) is initial among all families of smooth genus-\(g\) curves
54	  with level-\(\ell\) structure.
55	\end{definition}
56	
57	\section{Geometric properties}
58	
59	\begin{proposition}[Quasi-projectivity of \(\mathbb{M}_g\)]
60	  \label{prop:Mg_quasiprojective}
61	  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.mgQuasiProjective}
62	  \uses{def:Mg_level}
63	  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
64	  % SOURCE QUOTE: "It is known that $\mathbb{M}_g$ is a regular, quasi-projective variety of dimension $3g-3$. We regard it over $\IQbar$; it is irreducible according to our convention introduced below Theorem~\ref{ThmHtInequality}."
65	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
66	  For \(\ell \ge 3\), \(\mathbb{M}_g\) is a smooth, irreducible, quasi-projective variety over
67	  \(\overline{\mathbb{Q}}\) of dimension \(3g - 3\). It admits a compactification
68	  \(\overline{\mathbb{M}_g}\) (the Deligne--Mumford compactification by stable curves with
69	  level structure), which is a projective variety containing \(\mathbb{M}_g\) as a Zariski
70	  open dense subset.
71	\end{proposition}
72	
73	% SOURCE QUOTE PROOF: "It is known that $\mathbb{M}_g$ is a regular, quasi-projective variety of dimension $3g-3$. We regard it over $\IQbar$; it is irreducible according to our convention introduced below Theorem~\ref{ThmHtInequality}." (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
74	\begin{proof}
75	  \uses{def:Mg_level}
76	  The quasi-projectivity and regularity of \(\mathbb{M}_g\) are classical; see
77	  \cite[Chapter~XVI, Theorem~2.11]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or
78	  \cite[Theorem~1.8]{OortSteenbrink}. The dimension count \(\dim \mathbb{M}_g = 3g - 3\)
79	  is the Riemann count: a smooth curve of genus \(g \ge 2\) has \(3g - 3\) moduli.
80	  Irreducibility of \(\mathbb{M}_g\) over \(\overline{\mathbb{Q}}\) is a consequence of
81	  \cite[Theorem~5.15]{DM:irreducibility}. The Deligne--Mumford compactification
82	  \(\overline{\mathbb{M}_g}\) is constructed in \cite[Theorem~5.2]{DM:irreducibility} by
83	  allowing level structure on stable curves; it is projective by the valuative criterion and
84	  the properness of the moduli functor for stable curves.
85	\end{proof}
86	
87	\section{The Torelli map}
88	
89	\begin{lemma}[Torelli map is quasi-finite]
90	  \label{lem:torelli_quasi_finite}
91	  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.torelliQuasiFinite}
92	  \uses{def:Mg_level, def:universal_curve}
93	  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
94	  % SOURCE QUOTE: "As we have level structure, the Torelli morphism need not be injective on $\IC$-points, but it is finite-to-one on such points, \textit{cf.} \cite[Lemma 1.11]{OortSteenbrink}."
95	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
96	  The Torelli map \(\tau \colon \mathbb{M}_g \to \mathbb{A}_g\), sending a genus-\(g\) curve
97	  \([C]\) to its principally polarized Jacobian \([\mathrm{Jac}(C)]\), is quasi-finite. Here
98	  \(\mathbb{A}_g\) denotes the fine moduli space of principally polarized abelian varieties of
99	  dimension \(g\) with level-\(\ell\) structure.
100	\end{lemma}
101	
102	% SOURCE QUOTE PROOF: "The Torelli map $\tau$ is quasi-finite; see \cite[Lemma 1.11]{OortSteenbrink}." (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
103	\begin{proof}
104	  \uses{def:Mg_level, def:universal_curve}
105	  By \cite[Lemma~1.11]{OortSteenbrink}, the Torelli map \(\tau\) is quasi-finite. More
106	  precisely, with level-\(\ell\) structure for \(\ell \ge 3\), the classical Torelli theorem
107	  (which asserts injectivity on \(\mathbb{C}\)-points for the coarse moduli space) implies
108	  that the fibers of \(\tau\) over \(\mathbb{C}\)-points are finite. Combined with the fact
109	  that \(\tau\) is of finite type (as a morphism between quasi-projective varieties of finite
110	  type over \(\overline{\mathbb{Q}}\)), quasi-finiteness follows.
111	\end{proof}
